+function resolveSlidesStreamFallback(env: Record<string, string | undefined>): boolean {
+  const raw = env.SLIDES_EXTRACT_STREAM?.trim().toLowerCase()
+  return raw === '1' || raw === 'true' || raw === 'yes'
